using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["version"] = "1.0.0",
        ["features"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["notifications"] = true,
            ["betaFeatures"] = false
        },
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30
    };

    [McpServerResource(UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAppConfig()
    {
        return JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions
        {
            WriteIndented = true
        });
    }

    [McpServerResource(UriTemplate = "config://app/features",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns current feature flag settings.")]
    public static string GetFeatureFlags()
    {
        var features = AppConfig["features"];
        return JsonSerializer.Serialize(features, new JsonSerializerOptions
        {
            WriteIndented = true
        });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Checks if a specific feature flag is enabled.")]
    public static string CheckFeature(
        [Description("The feature flag name to check (e.g., darkMode, notifications)")] string featureName)
    {
        var features = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["notifications"] = true,
            ["betaFeatures"] = false
        };

        if (features.TryGetValue(featureName, out var enabled))
        {
            return $"Feature '{featureName}' is {(enabled ? "enabled" : "disabled")}.";
        }

        return $"Feature '{featureName}' not found. Available: {string.Join(", ", features.Keys)}";
    }

    [McpServerTool, Description("Returns the server uptime and status information.")]
    public static string GetServerStatus()
    {
        return $"Server is running. Started at: {DateTime.UtcNow:O}. Environment: production.";
    }
}

